```kotlin
// notification/src/main/kotlin/.../NotificationWebSocketHandler.kt

@Component
class NotificationWebSocketHandler(
    private val sessionRegistry: WebSocketSessionRegistry,
    private val pendingNotificationService: PendingNotificationService,
) : TextWebSocketHandler() {

    override fun afterConnectionEstablished(session: WebSocketSession) {
        val userId = session.extractUserId() // JWT에서 추출
        sessionRegistry.register(userId, session)
        // 재접속 시 미수신 알림 즉시 전송
        pendingNotificationService.flushPending(userId, session)
    }

    override fun afterConnectionClosed(session: WebSocketSession, status: CloseStatus) {
        sessionRegistry.unregister(session)
    }
}
```

```kotlin
// notification/src/main/kotlin/.../WebSocketSessionRegistry.kt

@Component
class WebSocketSessionRegistry(
    private val redisTemplate: StringRedisTemplate,
) {
    // 로컬 세션 맵 (현재 서버 인스턴스)
    private val localSessions = ConcurrentHashMap<String, WebSocketSession>()

    fun register(userId: String, session: WebSocketSession) {
        localSessions[session.id] = session
        redisTemplate.opsForSet().add("ws:session:$userId", session.id)
        redisTemplate.expire("ws:session:$userId", Duration.ofHours(24))
    }

    fun findSessionsByUserId(userId: String): List<WebSocketSession> {
        val sessionIds = redisTemplate.opsForSet().members("ws:session:$userId") ?: return emptyList()
        return sessionIds.mapNotNull { localSessions[it] }.filter { it.isOpen }
    }

    fun unregister(session: WebSocketSession) {
        localSessions.remove(session.id)
        // Redis에서 해당 sessionId 제거 (userId 조회 후)
    }
}
```

