#### APNs 서비스

```kotlin
// notification/src/main/kotlin/.../ApnsNotificationSender.kt

@Component
class ApnsNotificationSender(
    @Value("\${apns.key-id}") private val keyId: String,
    @Value("\${apns.team-id}") private val teamId: String,
    @Value("\${apns.bundle-id}") private val bundleId: String,
    @Value("\${apns.p8-key-path}") private val p8KeyPath: String,
    @Value("\${apns.sandbox:false}") private val sandbox: Boolean,
) : NotificationSender {

    private val apnsClient: ApnsClient by lazy { buildClient() }

    private fun buildClient(): ApnsClient {
        val builder = ApnsClientBuilder()
            .setSigningKey(ApnsSigningKey.loadFromPkcs8File(File(p8KeyPath), teamId, keyId))

        return if (sandbox) {
            builder.setApnsServer(ApnsClientBuilder.DEVELOPMENT_APNS_HOST).build()
        } else {
            builder.setApnsServer(ApnsClientBuilder.PRODUCTION_APNS_HOST).build()
        }
    }

    override suspend fun send(deviceToken: String, payload: NotificationPayload): SendResult {
        val apsPayload = SimpleApnsPushNotification(
            deviceToken,
            bundleId,
            buildApsPayload(payload),
        )
        val response = apnsClient.sendNotification(apsPayload).await()

        return if (response.isAccepted) {
            SendResult.Success
        } else {
            SendResult.Failure(response.rejectionReason ?: "Unknown")
        }
    }

    private fun buildApsPayload(payload: NotificationPayload): String {
        return """
        {
          "aps": {
            "alert": {
              "title": "${payload.title}",
              "body": "${payload.body}"
            },
            "sound": "default",
            "badge": ${payload.badge ?: 0}
          },
          "data": ${payload.dataJson()}
        }
        """.trimIndent()
    }
}
```

