### Phase 4: 알림 라우터 및 미수신 재전송 (1-2주)

**영향 모듈:** `notification/`, `domain/`

#### 알림 라우팅 로직

```kotlin
// notification/src/main/kotlin/.../NotificationRouter.kt

@Service
class NotificationRouter(
    private val sessionRegistry: WebSocketSessionRegistry,
    private val apnsSender: ApnsNotificationSender,
    private val deviceTokenRepository: DeviceTokenRepository,
    private val notificationHistoryRepository: NotificationHistoryRepository, // DynamoDB
    private val settingRepository: NotificationSettingRepository,
) {

    suspend fun route(userId: String, payload: NotificationPayload) {
        // 1. 알림 설정 확인
        val setting = settingRepository.findByUserId(userId) ?: return
        if (!setting.isEnabled(payload.type)) return

        // 2. DynamoDB에 PENDING 상태로 저장
        val history = notificationHistoryRepository.save(
            NotificationHistory(
                userId = userId,
                payload = payload,
                status = NotificationStatus.PENDING,
            )
        )

        // 3. WebSocket 세션이 있으면 즉시 전송 (포그라운드)
        val wsSessions = sessionRegistry.findSessionsByUserId(userId)
        if (wsSessions.isNotEmpty()) {
            wsSessions.forEach { session ->
                session.sendMessage(TextMessage(payload.toJson()))
            }
            notificationHistoryRepository.updateStatus(history.id, NotificationStatus.DELIVERED)
            return
        }

        // 4. iOS: APNs로 백그라운드 알림 전송
        val iosTokens = deviceTokenRepository.findByUserIdAndPlatformAndIsActiveTrue(userId, Platform.IOS.value)
        iosTokens.forEach { token ->
            val result = apnsSender.send(token.token, payload)
            if (result is SendResult.Failure) {
                // 유효하지 않은 토큰 비활성화
                if (result.reason == "BadDeviceToken" || result.reason == "Unregistered") {
                    token.isActive = false
                    deviceTokenRepository.save(token)
                }
            }
        }

        // 5. Android: 미수신 상태 유지 (재접속 시 전송)
        // PENDING 상태 유지 → WebSocket 재연결 시 flushPending() 호출
        if (iosTokens.isNotEmpty()) {
            notificationHistoryRepository.updateStatus(history.id, NotificationStatus.DELIVERED)
        }
    }
}
```

#### 미수신 알림 재전송

```kotlin
// notification/src/main/kotlin/.../PendingNotificationService.kt

@Service
class PendingNotificationService(
    private val notificationHistoryRepository: NotificationHistoryRepository,
) {
    fun flushPending(userId: String, session: WebSocketSession) {
        val pending = notificationHistoryRepository.findPendingByUserId(userId)
        pending.forEach { notification ->
            session.sendMessage(TextMessage(notification.toJson()))
            notificationHistoryRepository.updateStatus(notification.id, NotificationStatus.DELIVERED)
        }
    }
}
